                                  className="bg-gray-800 border-gray-600 text-white"
                                  placeholder="2020"
                                  type="number"
                                  min="1900"
                                  max={new Date().getFullYear()}
                                />
                              </FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                      </div>

                      <div className="flex gap-3">
                        <Button 
                          type="submit" 
                          className="flex-1 bg-blue-600 text-white hover:bg-blue-700"
                          disabled={updateBusinessMutation.isPending}
                        >
                          {updateBusinessMutation.isPending ? (
                            <div className="flex items-center gap-2">
                              <div className="animate-spin w-4 h-4 border-2 border-white border-t-transparent rounded-full" />
                              Saving...
                            </div>
                          ) : (
                            <>
                              <Save className="w-4 h-4 mr-2" />
                              {hasBusinessProfile ? "Update Business Profile" : "Create Business Profile"}
                            </>
                          )}
                        </Button>

                        {hasBusinessProfile && (
                          <Button 
                            type="button"
                            variant="outline"
                            className="border-red-500 text-red-500 hover:bg-red-500 hover:text-white"
                            disabled={deleteBusinessMutation.isPending}
                            onClick={() => {
                              if (confirm("Are you sure you want to delete your business profile? This action cannot be undone.")) {
                                deleteBusinessMutation.mutate();
                              }
                            }}
                          >
                            {deleteBusinessMutation.isPending ? (
                              <div className="flex items-center gap-2">
                                <div className="animate-spin w-4 h-4 border-2 border-red-500 border-t-transparent rounded-full" />
                                Deleting...
                              </div>
                            ) : (
                              <>
                                <X className="w-4 h-4 mr-2" />
                                Delete Profile
                              </>
                            )}
                          </Button>
                        )}
                      </div>
                    </form>
                  </Form>
                </CardContent>
              </Card>
            </TabsContent>
          </Tabs>
        </div>
      </div>
    </>
  );
}

