  /* Subtle border styling for dark mode */
  .dark .border-primary,
  .dark .border-border {
    border-color: hsl(var(--border));
  }

  /* Dark mode main content areas */
  .dark main {
    background-color: black;
  }

  /* Header gradient shadow styling */
  .header-gradient-shadow {
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.15);
  }

  /* Dark mode header gradient shadow */
  .dark .header-gradient-shadow {
    box-shadow: 0 2px 16px rgba(0, 0, 0, 0.5), 0 1px 6px rgba(0, 0, 0, 0.3);
  }

  /* Bottom navigation gradient shadow styling (flipped) */
  .bottom-nav-gradient-shadow {
    box-shadow: 0 -2px 12px rgba(0, 0, 0, 0.15);
  }

  /* Dark mode bottom navigation gradient shadow */
  .dark .bottom-nav-gradient-shadow {
    box-shadow: 0 -2px 16px rgba(0, 0, 0, 0.5), 0 -1px 6px rgba(0, 0, 0, 0.3);
  }

  /* Make all page borders thinner */
  .border-b {
    border-bottom-width: 1px !important;
  }

  .border-t {
    border-top-width: 1px !important;
  }

  .border {
    border-width: 1px !important;
  }

  /* Hide scrollbar on mobile */
  .scrollbar-hide {
    -ms-overflow-style: none;  /* IE and Edge */
    scrollbar-width: none;  /* Firefox */
  }

  .scrollbar-hide::-webkit-scrollbar {
    display: none;  /* Chrome, Safari, and Opera */
  }
}

