import { useQuery } from "@tanstack/react-query";
import { useParams, Link, useLocation } from "wouter";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ArrowLeft } from "lucide-react";
import { PlatformPostCard } from "@/components/PlatformPostCard";
import { MinistryPostCard } from "@/components/MinistryPostCard";

export default function PostPage() {
  const { id } = useParams();
  const [location] = useLocation();
  const postId = parseInt(id || '0');

  // Determine if this is a ministry post based on the URL
  const isMinistryPost = location.startsWith('/ministry-post/');

  const { data: post, isLoading, error } = useQuery({
    queryKey: isMinistryPost ? [`/api/ministry-posts/${postId}`] : [`/api/platform-posts/${postId}`],
    enabled: !!postId && !isNaN(postId),
    refetchOnMount: true,
    refetchOnWindowFocus: true,
  });

  const { data: currentUser } = useQuery({
    queryKey: ["/api/user"],
  });

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black text-white">
        <div className="container mx-auto px-4 py-8">
          <div className="animate-pulse">
            <div className="h-4 bg-gray-700 rounded w-1/4 mb-6"></div>
            <Card className="bg-black border-gray-800">
              <CardContent className="p-6">
                <div className="space-y-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-gray-700 rounded-full"></div>
                    <div className="space-y-2">
                      <div className="h-4 bg-gray-700 rounded w-32"></div>
                      <div className="h-3 bg-gray-700 rounded w-24"></div>
                    </div>
                  </div>
                  <div className="h-4 bg-gray-700 rounded w-3/4"></div>
                  <div className="h-32 bg-gray-700 rounded"></div>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    );
  }

  if (error || !post) {
    return (
      <div className="min-h-screen bg-black text-white">
        <div className="container mx-auto px-4 py-8">
          <Link href="/feed">
            <Button variant="ghost" className="text-[#D4AF37] hover:text-white hover:bg-gray-800 mb-6">
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Feed
            </Button>
          </Link>

          <Card className="bg-black border-gray-800">
            <CardContent className="p-6 text-center">
              <h2 className="text-xl font-semibold text-white mb-2">Post Not Found</h2>
              <p className="text-gray-400">The post you're looking for doesn't exist or has been removed.</p>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white">
      <div className="container mx-auto px-4 py-8">
        <Link href="/feed">
          <Button variant="ghost" className="text-[#D4AF37] hover:text-white hover:bg-gray-800 mb-6">
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Feed
          </Button>
        </Link>

        <div className="max-w-2xl mx-auto">
          {isMinistryPost ? (
            <MinistryPostCard 
              post={post} 
              disableClick={true}
              flatLayout={true}
            />
          ) : (
            <PlatformPostCard 
              post={post} 
              currentUserId={currentUser?.id}
              showActions={true}
              expandComments={true}
              disablePostClick={true}
            />
          )}
        </div>
      </div>
    </div>
  );
}

ios/App/App/public/disable-errors.js.content:
// Script to disable the error overlay
window.addEventListener('load', function() {
  // Try to disable the error overlay by setting the config option
  try {
    // This is the direct way to disable the error overlay
    window.server = window.server || {};
    window.server.hmr = window.server.hmr || {};
    window.server.hmr.overlay = false;

    // Also try to disable by direct attribute
    if (window.__vite_plugin_react_preamble_installed__) {
      window.__vite_plugin_react_preamble_installed__ = false;
    }

    // Also try to capture and prevent errors
    window.addEventListener('error', function(event) {
      if (event.message && event.message.includes('Failed to fetch')) {
        console.warn('Suppressed error:', event.message);
        event.preventDefault();
        event.stopPropagation();
        return true;
      }
    }, true);

    // Handle unhandled promise rejections
    window.addEventListener('unhandledrejection', function(event) {
      console.warn('Suppressed rejection:', event.reason);
      event.preventDefault();
      event.stopPropagation();
      return true;
    }, true);

    // Additional attempts to disable the error overlay
    if (window.__vite_plugin_runtime_error_overlay) {
      window.__vite_plugin_runtime_error_overlay.clearRuntimeErrors = function() {};
      window.__vite_plugin_runtime_error_overlay.onError = function() {};
    }

    console.log('Error overlay disabled via external script');
  } catch (e) {
    console.error('Failed to disable error overlay:', e);
  }
});

