      type: "follow",
      title: "New Follower",
      message: `${follower.displayName || follower.firstName || follower.username} started following you`,
      relatedId: followerId,
      relatedType: "user",
      actorId: followerId,
      actorName: follower.displayName || follower.firstName || follower.username,
