  async savePost(userId: string, postId: number): Promise<SavedPost> {
    const [saved] = await db
      .insert(savedPosts)
      .values({ userId, postId })
      .onConflictDoNothing()
      .returning();
    if (!saved) {
      const [existing] = await db
        .select()
        .from(savedPosts)
        .where(and(eq(savedPosts.userId, userId), eq(savedPosts.postId, postId)))
        .limit(1);
      return existing;
    }
    return saved;
  }

