import { useState, useEffect } from 'react';
import { useParams, Link } from 'wouter';
import { useQuery, useMutation } from '@tanstack/react-query';
import { Elements, PaymentElement, useStripe, useElements } from '@stripe/react-stripe-js';
import { loadStripe } from '@stripe/stripe-js';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Separator } from '@/components/ui/separator';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/hooks/useAuth';
import { apiRequest } from '@/lib/queryClient';
import { ArrowLeft, Heart, Users, Lock } from 'lucide-react';
import { Campaign } from '@shared/schema';

// Load Stripe
const stripePromise = loadStripe(import.meta.env.VITE_STRIPE_PUBLIC_KEY || '');

const PRESET_AMOUNTS = [10, 20, 30, 50, 100, 150];

function CheckoutForm({ campaign, amount, tip }: { campaign: Campaign; amount: number; tip: number }) {
  const stripe = useStripe();
  const elements = useElements();
  const { toast } = useToast();
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!stripe || !elements) {
      return;
    }

    setIsProcessing(true);

    try {
      const { error } = await stripe.confirmPayment({
        elements,
        confirmParams: {
          return_url: `${window.location.origin}/donate/${campaign.slug}?success=true&campaignId=${campaign.id}`,
        },
      });

      if (error) {
        toast({
          title: "Payment Failed",
          description: error.message,
          variant: "destructive",
        });
      }
    } catch (error) {
      toast({
        title: "Payment Error",
        description: "An unexpected error occurred. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsProcessing(false);
    }
  };

  const totalAmount = amount + tip;

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="bg-gray-50 p-4 rounded-lg">
        <div className="flex justify-between items-center mb-2">
          <span className="text-sm text-gray-600">Your donation</span>
          <span className="font-semibold text-black">${amount.toFixed(2)}</span>
        </div>
        {tip > 0 && (
          <div className="flex justify-between items-center mb-2">
            <span className="text-sm text-gray-600">Tip Christ Collective</span>
            <span className="font-semibold text-black">${tip.toFixed(2)}</span>
          </div>
        )}
        <Separator className="my-2" />
        <div className="flex justify-between items-center">
          <span className="font-semibold text-black">Total</span>
          <span className="font-bold text-lg text-black">${totalAmount.toFixed(2)}</span>
        </div>
      </div>

      <div className="space-y-4">
        <h3 className="font-semibold text-lg">Payment method</h3>
        <PaymentElement />
      </div>

      <Button 
        type="submit" 
        disabled={!stripe || isProcessing}
        className="w-full bg-primary hover:bg-primary/90 text-white font-semibold py-3 text-lg"
      >
        {isProcessing ? 'Processing...' : `Donate $${totalAmount.toFixed(2)}`}
      </Button>

      <div className="flex items-center justify-center text-sm text-gray-500">
        <Lock className="w-4 h-4 mr-1" />
        Your payment information is secure and encrypted
      </div>
    </form>
  );
}

export default function DonationCheckoutPage() {
  const { campaignId } = useParams();
  const [amount, setAmount] = useState(30);
  const [customAmount, setCustomAmount] = useState('');
  const [tip, setTip] = useState(0);
  const [clientSecret, setClientSecret] = useState('');
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const { toast } = useToast();
  const { user } = useAuth();
  const isAuthenticated = !!user;

  const { data: campaign, isLoading: isLoadingCampaign } = useQuery<Campaign>({
    queryKey: [`/api/campaigns/${campaignId}`],
  });

  const createPaymentIntentMutation = useMutation({
    mutationFn: async (donationAmount: number) => {
      const response = await apiRequest('/api/donations/create-payment-intent', {
        method: 'POST',
        data: {
          campaignId,
          amount: donationAmount + tip,
          guestInfo: {
            firstName,
            lastName,
            email
          }
        }
      });
      return response.json();
    },
    onSuccess: (data) => {
      setClientSecret(data.clientSecret);
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to initialize payment. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Only create payment intent when user initiates payment
  const initializePayment = () => {
    // Validate guest information if user is not authenticated
    if (!isAuthenticated) {
      if (!firstName.trim() || !lastName.trim() || !email.trim()) {
        toast({
          title: "Missing Information",
          description: "Please fill in your name and email address to continue.",
          variant: "destructive",
        });
        return;
      }

      // Basic email validation
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(email)) {
        toast({
          title: "Invalid Email",
          description: "Please enter a valid email address.",
          variant: "destructive",
        });
        return;
      }
    }

    if (campaignId && amount > 0) {
      createPaymentIntentMutation.mutate(amount);
    }
  };

  const handleAmountSelect = (selectedAmount: number) => {
    console.log('Amount selected:', selectedAmount);
    setAmount(selectedAmount);
    setCustomAmount('');
  };

  const handleCustomAmountChange = (value: string) => {
    setCustomAmount(value);
    const numValue = parseFloat(value);
    if (!isNaN(numValue) && numValue > 0) {
      setAmount(numValue);
    }
  };

  const calculateTip = (percentage: number) => {
    setTip(amount * (percentage / 100));
  };

  function formatCurrency(amount: string | number): string {
    const value = typeof amount === 'string' ? parseFloat(amount) : amount;
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(value || 0);
  }

  if (isLoadingCampaign) {
    return (
      <div className="min-h-screen bg-gray-50 py-8">
        <div className="container mx-auto px-4">
          <div className="max-w-2xl mx-auto">
            <div className="animate-pulse">
              <div className="h-8 bg-gray-200 rounded mb-4 w-1/3" />
              <div className="bg-white rounded-lg shadow-sm p-6">
                <div className="h-6 bg-gray-200 rounded mb-4 w-2/3" />
                <div className="h-4 bg-gray-100 rounded mb-2 w-full" />
                <div className="h-4 bg-gray-100 rounded mb-4 w-3/4" />
                <div className="grid grid-cols-3 gap-2 mb-4">
                  {[1, 2, 3, 4, 5, 6].map(i => (
                    <div key={i} className="h-12 bg-gray-200 rounded" />
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (!campaign) {
    return (
      <div className="min-h-screen bg-gray-50 py-8">
        <div className="container mx-auto px-4">
          <div className="max-w-2xl mx-auto text-center">
            <h1 className="text-2xl font-bold mb-4">Campaign Not Found</h1>
            <p className="text-gray-600 mb-6">The campaign you're trying to donate to doesn't exist.</p>
            <Link href="/donate" className="text-primary hover:text-primary/80 font-medium">
              ← Back to All Campaigns
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <div className="max-w-2xl mx-auto">
          {/* Header */}
          <div className="mb-6">
            <Link href={`/donate/${campaign.slug}`} className="inline-flex items-center text-primary hover:text-primary/80 font-medium mb-4">
              <ArrowLeft className="w-4 h-4 mr-1" />
              Fundraiser
            </Link>
          </div>

          {/* Main Content */}
          <Card className="shadow-sm">
            <CardHeader className="pb-4">
              <div className="flex items-center space-x-4">
                {campaign.image ? (
                  <img 
                    src={campaign.image} 
                    alt={campaign.title}
                    className="w-16 h-16 object-cover rounded-lg"
                  />
                ) : (
                  <div className="w-16 h-16 bg-gray-200 rounded-lg flex items-center justify-center">
                    <Heart className="w-8 h-8 text-gray-400" />
                  </div>
                )}
                <div>
                  <p className="text-sm text-[#D4AF37] mb-1">You're supporting</p>
                  <CardTitle className="text-xl">{campaign.title}</CardTitle>
                  <p className="text-sm text-[#D4AF37]">Your donation will benefit Christ Collective</p>
                </div>
              </div>
            </CardHeader>

            <CardContent className="space-y-6">
              {/* Amount Selection */}
              <div>
                <Label className="text-base font-semibold mb-4 block">Enter your donation</Label>

                {/* Preset amounts */}
                <div className="grid grid-cols-3 gap-2 mb-4">
                  {PRESET_AMOUNTS.map((presetAmount) => (
                    <Button
                      key={presetAmount}
                      variant={amount === presetAmount && !customAmount ? "default" : "outline"}
                      className={`h-12 relative ${
                        amount === presetAmount && !customAmount 
                          ? "bg-primary text-white border-primary" 
                          : "bg-white border-gray-200 text-gray-700 hover:border-gray-300"
                      }`}
                      onClick={() => handleAmountSelect(presetAmount)}
                    >
                      ${presetAmount}
                      {presetAmount === 30 && (
                        <span className="absolute -top-2 -right-2 bg-green-500 text-white text-xs px-2 py-1 rounded-full">
                          SUGGESTED
                        </span>
                      )}
                    </Button>
                  ))}
                </div>

                {/* Custom amount */}
                <div className="relative">
                  <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-2xl font-bold text-[#D4AF37]">
                    $
                  </span>
                  <Input
                    type="number"
                    placeholder="0.00"
                    value={customAmount || (amount > 0 ? amount.toString() : '')}
                    onChange={(e) => handleCustomAmountChange(e.target.value)}
                    className="pl-8 text-2xl font-bold h-14 text-right pr-16"
                    min="1"
                    step="0.01"
                  />
                  <span className="absolute right-3 top-1/2 transform -translate-y-1/2 text-lg text-[#D4AF37]">
                    USD
                  </span>
                </div>
              </div>

              {/* Tip Section */}
              <div className="bg-gray-50 p-4 rounded-lg">
                <div className="flex justify-between items-center mb-3">
                  <div>
                    <h4 className="font-semibold text-black">Tip Christ Collective services</h4>
                    <p className="text-sm text-gray-600">
                      Christ Collective has a 0% platform fee for organizers. Christ Collective will continue offering its 
                      services thanks to donors who will leave an optional amount here:
                    </p>
                  </div>
                </div>

                <div className="flex items-center space-x-2 mb-4">
                  <span className="text-2xl font-bold text-black">{amount > 0 ? ((tip / amount) * 100).toFixed(1) : '0.0'}%</span>
                </div>

                <div className="flex space-x-2 mb-4">
                  <Button
                    variant={Math.abs(tip - amount * 0.05) < 0.01 ? "default" : "outline"}
                    size="sm"
                    onClick={() => calculateTip(5)}
                    className="text-xs"
                  >
                    5%
                  </Button>
                  <Button
                    variant={Math.abs(tip - amount * 0.15) < 0.01 ? "default" : "outline"}
                    size="sm"
                    onClick={() => calculateTip(15)}
                    className="text-xs"
                  >
                    15%
                  </Button>
                  <Button
                    variant={Math.abs(tip - amount * 0.25) < 0.01 ? "default" : "outline"}
                    size="sm"
                    onClick={() => calculateTip(25)}
                    className="text-xs"
                  >
                    25%
                  </Button>
                  <Button
                    variant={tip === 0 ? "default" : "outline"}
                    size="sm"
                    onClick={() => setTip(0)}
                    className="text-xs"
                  >
                    No Tip
                  </Button>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="custom-tip" className="text-sm font-medium text-[#D4AF37]">Enter custom tip amount</Label>
                  <div className="relative">
                    <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-500">$</span>
                    <Input
                      id="custom-tip"
                      type="number"
                      placeholder="0.00"
                      value={tip > 0 ? tip.toFixed(2) : ''}
                      onChange={(e) => {
                        const value = parseFloat(e.target.value);
                        if (!isNaN(value) && value >= 0) {
                          setTip(value);
                        } else if (e.target.value === '') {
                          setTip(0);
                        }
                      }}
                      className="pl-8 pr-4"
                      min="0"
                      step="0.01"
                    />
                  </div>
                </div>
              </div>

              {/* Guest Information - Only show if not authenticated */}
              {!isAuthenticated && (
                <div className="bg-gray-100 p-4 rounded-lg">
                  <h4 className="font-semibold text-black mb-3">Donor Information</h4>
                  <p className="text-sm text-gray-600 mb-4">
                    Please provide your information to receive a donation receipt.
                  </p>

                  <div className="grid grid-cols-2 gap-4 mb-4">
                    <div>
                      <Label htmlFor="firstName" className="text-sm font-medium">First Name *</Label>
                      <Input
                        id="firstName"
                        type="text"
                        placeholder="Enter first name"
                        value={firstName}
                        onChange={(e) => setFirstName(e.target.value)}
                        className="mt-1"
                        required
                      />
                    </div>
                    <div>
                      <Label htmlFor="lastName" className="text-sm font-medium">Last Name *</Label>
                      <Input
                        id="lastName"
                        type="text"
                        placeholder="Enter last name"
                        value={lastName}
                        onChange={(e) => setLastName(e.target.value)}
                        className="mt-1"
                        required
                      />
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="email" className="text-sm font-medium">Email Address *</Label>
                    <Input
                      id="email"
                      type="email"
                      placeholder="Enter email address"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className="mt-1"
                      required
                    />
                    <p className="text-xs text-gray-500 mt-1">
                      Your receipt will be sent to this email address.
                    </p>
                  </div>
                </div>
              )}

              {/* Payment Form */}
              {clientSecret ? (
                <Elements 
                  key={clientSecret} // Force remount when clientSecret changes
                  stripe={stripePromise} 
                  options={{ 
                    clientSecret,
                    appearance: {
                      theme: 'stripe',
                    }
                  }}
                >
                  <CheckoutForm campaign={campaign} amount={amount} tip={tip} />
                </Elements>
              ) : createPaymentIntentMutation.isPending ? (
                <div className="text-center py-8">
                  <div className="animate-spin w-8 h-8 border-4 border-primary border-t-transparent rounded-full mx-auto" />
                  <p className="text-gray-600 mt-2">Initializing payment...</p>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="bg-gray-50 p-4 rounded-lg">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-sm text-gray-600">Your donation</span>
                      <span className="font-semibold text-black">${amount.toFixed(2)}</span>
                    </div>
                    {tip > 0 && (
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-sm text-gray-600">Tip</span>
                        <span className="text-sm text-gray-600">${tip.toFixed(2)}</span>
                      </div>
                    )}
                    <hr className="my-2" />
                    <div className="flex justify-between items-center">
                      <span className="font-semibold text-black">Total</span>
                      <span className="font-bold text-black">${(amount + tip).toFixed(2)}</span>
                    </div>
                  </div>

                  <Button 
                    onClick={initializePayment}
                    disabled={amount <= 0 || createPaymentIntentMutation.isPending}
                    className="w-full bg-primary hover:bg-primary/90 text-white py-6 text-lg font-semibold"
                  >
                    Proceed to Payment
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Footer Info */}
          <div className="mt-6 text-center text-sm text-gray-600">
            <p>
              By continuing, you agree with Christ Collective's{' '}
              <Link href="/terms" className="text-primary hover:underline">terms</Link> and{' '}
              <Link href="/privacy" className="text-primary hover:underline">privacy policy</Link>.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

client/src/pages/MinistryProfileViewPage.content:
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useRoute } from "wouter";
import { Helmet } from "react-helmet";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Separator } from "@/components/ui/separator";
import { useToast } from "@/hooks/use-toast";
import { 
  Building, 
  MapPin, 
  Phone, 
  Mail, 
  ExternalLink, 
  Users,
  Calendar,
  Heart,
  Share2,
  ArrowLeft,
  Clock,
  Globe,
  UserPlus,
  UserMinus
} from "lucide-react";
import { Link } from "wouter";
import { MinistryProfile, MinistryEvent } from "@shared/schema";
import { buildApiUrl } from "@/lib/api-config";

export default function MinistryProfileViewPage() {
  const [match, params] = useRoute("/ministry/:id");
  const ministryId = params?.id;
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const { data: ministry, isLoading } = useQuery({
    queryKey: ["/api/ministries", ministryId],
    queryFn: async () => {
      const response = await fetch(buildApiUrl(`/api/ministries/${ministryId}`), {
        credentials: 'include',
      });
      if (!response.ok) throw new Error("Ministry not found");
      return response.json();
    },
    enabled: !!ministryId,
  });

  // Fetch ministry events
  const { data: events = [], isLoading: isLoadingEvents } = useQuery({
    queryKey: ["/api/ministries", ministryId, "events"],
    queryFn: async () => {
      const response = await fetch(buildApiUrl(`/api/ministries/${ministryId}/events?t=${Date.now()}`), {
        credentials: 'include',
      });
      if (!response.ok) throw new Error("Failed to fetch events");
      return response.json();
    },
    enabled: !!ministryId,
    staleTime: 0,
    gcTime: 0
  });

  // Check if user is authenticated
  const { data: currentUser } = useQuery({
    queryKey: ["/api/user"],
    queryFn: async () => {
      const response = await fetch(buildApiUrl("/api/user"), {
        credentials: 'include',
      });
      if (!response.ok) return null;
      return response.json();
    },
  });

  // Check if user is following this ministry
  const { data: isFollowing = false } = useQuery({
    queryKey: ["/api/ministries", ministryId, "following"],
    queryFn: async () => {
      if (!currentUser || !ministryId) return false;
      const response = await fetch(buildApiUrl(`/api/ministries/${ministryId}/following`), {
        credentials: 'include',
      });
      if (!response.ok) return false;
      const data = await response.json();
      return data.isFollowing;
    },
    enabled: !!currentUser && !!ministryId,
  });

  // Follow/unfollow mutations
  const followMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch(buildApiUrl(`/api/ministries/${ministryId}/follow`), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
      });
      if (!response.ok) throw new Error('Failed to follow ministry');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/ministries", ministryId, "following"] });
      toast({
        title: "Success",
        description: "You are now following this ministry!",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to follow ministry. Please try again.",
        variant: "destructive",
      });
    },
  });

  const unfollowMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch(buildApiUrl(`/api/ministries/${ministryId}/follow`), {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
      });
      if (!response.ok) throw new Error('Failed to unfollow ministry');
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/ministries", ministryId, "following"] });
      toast({
        title: "Success",
        description: "You have unfollowed this ministry.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to unfollow ministry. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleFollowToggle = () => {
    if (isFollowing) {
      unfollowMutation.mutate();
    } else {
      followMutation.mutate();
    }
  };

  // Don't show follow button if user owns this ministry
  const isOwnMinistry = currentUser && ministry && ministry.userId === currentUser.id;

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black text-white">
        <div className="max-w-4xl mx-auto px-4 py-8">
          <div className="animate-pulse">
            <div className="h-8 bg-gray-700 rounded w-1/4 mb-8"></div>
            <div className="bg-gray-900 rounded-lg p-8">
              <div className="flex items-center space-x-6 mb-6">
                <div className="h-24 w-24 bg-gray-700 rounded-full"></div>
                <div className="flex-1">
                  <div className="h-8 bg-gray-700 rounded w-1/2 mb-2"></div>
                  <div className="h-4 bg-gray-700 rounded w-1/3 mb-4"></div>
                  <div className="flex gap-2">
                    <div className="h-6 bg-gray-700 rounded w-16"></div>
                    <div className="h-6 bg-gray-700 rounded w-16"></div>
                  </div>
                </div>
              </div>
              <div className="space-y-4">
                <div className="h-4 bg-gray-700 rounded"></div>
                <div className="h-4 bg-gray-700 rounded w-5/6"></div>
                <div className="h-4 bg-gray-700 rounded w-4/6"></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (!ministry) {
    return (
      <div className="min-h-screen bg-black text-white">
        <div className="max-w-4xl mx-auto px-4 py-8">
          <Link href="/ministries">
            <Button variant="ghost" className="mb-6 text-gray-300 hover:text-white">
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back to Ministries
            </Button>
          </Link>
          <Card className="bg-gray-900 border-gray-700">
            <CardContent className="p-8 text-center">
              <Building className="h-16 w-16 text-gray-600 mx-auto mb-4" />
              <h3 className="text-xl font-semibold text-gray-400 mb-2">Ministry Not Found</h3>
              <p className="text-gray-500">The ministry you're looking for doesn't exist or has been removed.</p>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <>
      <Helmet>
        <title>{ministry.name} - Ministry Profile | Christ Collective</title>
        <meta name="description" content={`Learn more about ${ministry.name}, a ${ministry.denomination} ministry serving the community.`} />
      </Helmet>

      <div className="min-h-screen bg-black text-white">
        <div className="max-w-4xl mx-auto px-4 py-8">
          {/* Back Button */}
          <Link href="/ministries">
            <Button variant="ghost" className="mb-6 text-gray-300 hover:text-white">
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back to Ministries
            </Button>
          </Link>

          {/* Ministry Header */}
          <Card className="bg-gray-900 border-gray-700 mb-6">
            <CardContent className="p-8">
              <div className="flex flex-col md:flex-row items-start md:items-center space-y-6 md:space-y-0 md:space-x-6">
                <Avatar className="h-24 w-24 mx-auto md:mx-0">
                  <AvatarImage src={ministry.logo} alt={ministry.name} />
                  <AvatarFallback className="bg-primary text-black text-3xl font-bold">
                    {ministry.name?.charAt(0) || 'M'}
                  </AvatarFallback>
                </Avatar>

                <div className="flex-1 text-center md:text-left">
                  <h1 className="text-3xl font-bold text-white mb-2">{ministry.name}</h1>
                  <div className="flex flex-wrap gap-2 justify-center md:justify-start mb-4">
                    {ministry.denomination && (
                      <Badge variant="outline" className="bg-[#D4AF37]/30 border-[#D4AF37] text-[#D4AF37]">
                        {ministry.denomination}
                      </Badge>
                    )}
                    {ministry.isVerified && (
                      <Badge className="bg-green-900/30 border-green-600 text-green-300">
                        ✓ Verified Ministry
                      </Badge>
                    )}
                  </div>

                  <div className="flex flex-wrap gap-3 justify-center md:justify-start">
                    {currentUser && !isOwnMinistry && (
                      <Button 
                        onClick={handleFollowToggle}
                        disabled={followMutation.isPending || unfollowMutation.isPending}
                        className={isFollowing ? "bg-gray-600 hover:bg-gray-700" : "bg-primary hover:bg-primary/90"}
                      >
                        {followMutation.isPending || unfollowMutation.isPending ? (
                          <div className="animate-spin rounded-full border-b-2 border-white h-4 w-4 mr-2"></div>
                        ) : isFollowing ? (
                          <UserMinus className="h-4 w-4 mr-2" />
                        ) : (
                          <UserPlus className="h-4 w-4 mr-2" />
                        )}
                        {isFollowing ? "Unfollow" : "Follow Ministry"}
                      </Button>
                    )}
                    <Button variant="outline" className="border-gray-600 hover:bg-gray-800">
                      <Heart className="h-4 w-4 mr-2" />
                      Support
                    </Button>
                    <Button variant="outline" className="border-gray-600 hover:bg-gray-800">
                      <Share2 className="h-4 w-4 mr-2" />
                      Share
                    </Button>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Ministry Details */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Main Content */}
            <div className="lg:col-span-2 space-y-6">
              {/* About Section */}
              <Card className="bg-gray-900 border-gray-700">
                <CardHeader>
                  <CardTitle className="text-white">About {ministry.name}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-gray-300 leading-relaxed">{ministry.description}</p>
                </CardContent>
              </Card>

              {/* Recent Posts Section */}
              <Card className="bg-gray-900 border-gray-700">
                <CardHeader>
                  <CardTitle className="text-white">Recent Updates</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-center py-8">
                    <Calendar className="h-12 w-12 text-gray-600 mx-auto mb-3" />
                    <p className="text-gray-400">No recent posts yet</p>
                    <p className="text-gray-500 text-sm">Check back later for updates from this ministry</p>
                  </div>
                </CardContent>
              </Card>

              {/* Upcoming Events Section */}
              <Card className="bg-gray-900 border-gray-700">
                <CardHeader>
                  <CardTitle className="text-white">Upcoming Events</CardTitle>
                </CardHeader>
                <CardContent>
                  {isLoadingEvents ? (
                    <div className="text-center py-8">
                      <div className="animate-spin rounded-full border-b-2 border-primary h-8 w-8 mx-auto mb-4"></div>
                      <p className="text-gray-400">Loading events...</p>
                    </div>
                  ) : events.length === 0 ? (
                    <div className="text-center py-8">
                      <Calendar className="h-12 w-12 text-gray-600 mx-auto mb-3" />
                      <p className="text-gray-400">No upcoming events</p>
                      <p className="text-gray-500 text-sm">Stay tuned for announcements</p>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {events.map((event: MinistryEvent) => (
                        <div 
                          key={event.id} 
                          className="border border-gray-700 rounded-lg p-4 hover:border-gray-600 transition-colors cursor-pointer"
                          onClick={() => {
                            // Navigate to the ministry post page for this event
                            // Events automatically create ministry posts, so we need to find the corresponding post
                            window.location.href = `/ministry-post/${event.id}`;
                          }}
                        >
                          <div className="flex gap-4">
                            {/* Event Flyer */}
                            {event.flyerImage && (
                              <div className="flex-shrink-0">
                                <img
                                  src={event.flyerImage}
                                  alt={`${event.title} flyer`}
                                  className="w-16 h-16 object-cover rounded-lg border border-gray-600"
                                />
                              </div>
                            )}

                            <div className="flex-1 min-w-0">
                              <h4 className="text-white font-semibold text-lg mb-2">{event.title}</h4>
                              <p className="text-gray-300 text-sm mb-3 line-clamp-2">{event.description}</p>

                              <div className="flex flex-wrap gap-4 text-sm text-gray-400">
                                <div className="flex items-center">
                                  <Calendar className="h-4 w-4 mr-1" />
                                  {new Date(event.startDate).toLocaleDateString()}
                                </div>
                                <div className="flex items-center">
                                  <Clock className="h-4 w-4 mr-1" />
                                  6:00 PM - 10:00 PM
                                </div>
                                {event.location && (
                                  <div className="flex items-center">
                                    <MapPin className="h-4 w-4 mr-1" />
                                    {event.location}
                                  </div>
                                )}
                                {event.isOnline && (
                                  <div className="flex items-center">
                                    <Globe className="h-4 w-4 mr-1" />
                                    Online Event
                                  </div>
                                )}
                              </div>

                              <div className="flex items-center justify-between mt-3">
                                <Badge variant="outline" className="border-gray-600 text-gray-300">
