import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { Plus, X, Upload, Image, Video, Type, Youtube, Loader2 } from "lucide-react";
import { buildApiUrl } from "@/lib/api-config";
import { MentionTextarea } from "@/components/MentionTextarea";

interface CreatePostModalProps {
  trigger?: React.ReactNode;
  onPostCreated?: () => void;
}



const MEDIA_TYPES = [
  { value: "image", label: "Image", icon: Image },
  { value: "video", label: "Video", icon: Video },
  { value: "text", label: "Text Only", icon: Type },
  { value: "youtube_channel", label: "YouTube Channel", icon: Youtube },
];

export function CreatePostModal({ trigger, onPostCreated }: CreatePostModalProps) {
  const [open, setOpen] = useState(false);
  const [formData, setFormData] = useState({
    title: "",
    content: "",
    authorType: "user",
    authorId: null,
    mediaType: "image",
    mediaUrls: [] as string[],
    tags: [] as string[],
  });
  const [newTag, setNewTag] = useState("");
  const [newMediaUrl, setNewMediaUrl] = useState("");
  const [uploading, setUploading] = useState(false);

  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Get user's profile data to determine available author types
  const { data: creatorStatus } = useQuery({
    queryKey: ["/api/user/creator-status"],
  });

  const { data: businessProfiles } = useQuery({
    queryKey: ["/api/business-profiles"],
  });

  const { data: ministryProfile } = useQuery({
    queryKey: ["/api/user/ministry-profile"],
  });

  const createPostMutation = useMutation({
    mutationFn: async (postData: any) => {
      const res = await apiRequest("/api/platform-posts", {
        method: "POST",
        data: postData,
      });
      const data = await res.json();
      return { status: res.status, data };
    },
    onSuccess: (result) => {
      if (result.status === 202) {
        toast({
          title: "Post submitted for review",
          description: "Your post will be visible once approved by a moderator.",
        });
      } else {
        toast({ title: "Post created successfully!" });
      }
      setOpen(false);
      resetForm();
      queryClient.invalidateQueries({ queryKey: ["/api/platform-posts"] });
      onPostCreated?.();
    },
    onError: (error: any) => {
      const msg = error.message || "";
      let description = "Something went wrong. Please try again.";
      if (msg.includes("community guidelines")) {
        description = "Your post contains content that violates our community guidelines.";
      } else if (msg.includes("400:")) {
        try {
          const jsonStr = msg.substring(msg.indexOf("{"));
          const parsed = JSON.parse(jsonStr);
          description = parsed.message || description;
        } catch {
          description = msg;
        }
      } else {
        description = msg;
      }
      toast({
        title: "Failed to create post",
        description,
        variant: "destructive",
      });
    },
  });

  const resetForm = () => {
    setFormData({
      title: "",
      content: "",
      authorType: "user",
      authorId: null,
      mediaType: "image",
      mediaUrls: [],
      tags: [],
    });
    setNewTag("");
    setNewMediaUrl("");
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.content.trim()) {
      toast({
        title: "Content required",
        description: "Please enter some content for your post",
        variant: "destructive",
      });
      return;
    }

    createPostMutation.mutate(formData);
  };

  const addTag = () => {
    if (newTag.trim() && !formData.tags.includes(newTag.trim())) {
      setFormData(prev => ({
        ...prev,
        tags: [...prev.tags, newTag.trim()]
      }));
      setNewTag("");
    }
  };

  const removeTag = (tagToRemove: string) => {
    setFormData(prev => ({
      ...prev,
      tags: prev.tags.filter(tag => tag !== tagToRemove)
    }));
  };

  const addMediaUrl = () => {
    if (newMediaUrl.trim() && !formData.mediaUrls.includes(newMediaUrl.trim())) {
      setFormData(prev => ({
        ...prev,
        mediaUrls: [...prev.mediaUrls, newMediaUrl.trim()]
      }));
      setNewMediaUrl("");
    }
  };

  const removeMediaUrl = (urlToRemove: string) => {
    setFormData(prev => ({
      ...prev,
      mediaUrls: prev.mediaUrls.filter(url => url !== urlToRemove)
    }));
  };

  const getAuthorOptions = () => {
    const options = [{ value: "user", label: "Personal Account", id: null }];

    if (creatorStatus && typeof creatorStatus === 'object' && 'isCreator' in creatorStatus && creatorStatus.isCreator && 'creatorProfile' in creatorStatus && creatorStatus.creatorProfile) {
      const creatorProfile = creatorStatus.creatorProfile as any;
      options.push({
        value: "creator",
        label: `Creator: ${creatorProfile.name}`,
        id: creatorProfile.id,
      });
    }

    if (Array.isArray(businessProfiles) && businessProfiles.length > 0) {
      businessProfiles.forEach((business: any) => {
        options.push({
          value: "business",
          label: `Business: ${business.companyName}`,
          id: business.id,
        });
      });
    }

    if (ministryProfile && typeof ministryProfile === 'object' && 'name' in ministryProfile && ministryProfile.name) {
      options.push({
        value: "ministry",
        label: `Ministry: ${ministryProfile.name}`,
        id: (ministryProfile as any).id,
      });
    }

    return options;
  };

  return (
    <div>
      {trigger ? (
        <div onClick={() => {
          setOpen(true);
        }}>
          {trigger}
        </div>
      ) : (
        <Button 
          onClick={() => {
            setOpen(true);
          }}
          className="bg-[#D4AF37] text-black hover:bg-[#B8941F]"
        >
          <Plus className="w-4 h-4 mr-2" />
          Create Post
        </Button>
      )}

      <Dialog open={open} onOpenChange={setOpen}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto bg-black border-gray-800">
        <DialogHeader>
          <DialogTitle className="text-white">Create New Post</DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Author Selection */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-white">Post As</label>
            <Select
              value={formData.authorType}
              onValueChange={(value) => {
                const option = getAuthorOptions().find(opt => opt.value === value);
                setFormData(prev => ({
                  ...prev,
                  authorType: value,
                  authorId: option?.id || null,
                }));
              }}
            >
              <SelectTrigger className="bg-[#0A0A0A] border-gray-800 text-white">
                <SelectValue />
              </SelectTrigger>
              <SelectContent className="bg-[#0A0A0A] border-gray-800">
                {getAuthorOptions().map((option) => (
                  <SelectItem key={option.value} value={option.value}>
                    {option.label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Title */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-white">Title (Optional)</label>
            <Input
              value={formData.title}
              onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
              placeholder="Add a title to your post..."
              className="bg-[#0A0A0A] border-gray-800 text-white placeholder-gray-500"
            />
          </div>

          {/* Content */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-white">Content *</label>
            <MentionTextarea
              value={formData.content}
              onChange={(content) => setFormData(prev => ({ ...prev, content }))}
              placeholder="What would you like to share? Type @ to mention someone..."
              rows={4}
              className="bg-[#0A0A0A] border-gray-800 text-white placeholder-gray-500"
              required
            />
            <p className="text-xs text-gray-500">Tip: Type @ followed by a username to tag someone</p>
          </div>

          {/* Media Type */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-white">Media Type</label>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
              {MEDIA_TYPES.map((type) => {
                const Icon = type.icon;
                return (
                  <Button
                    key={type.value}
                    type="button"
                    variant={formData.mediaType === type.value ? "default" : "outline"}
                    className={`flex items-center gap-2 ${
                      formData.mediaType === type.value
                        ? "bg-[#D4AF37] text-black hover:bg-[#B8941F]"
                        : "bg-[#0A0A0A] border-gray-800 text-white hover:bg-gray-900"
                    }`}
                    onClick={() => setFormData(prev => ({ ...prev, mediaType: type.value }))}
                  >
                    <Icon className="w-4 h-4" />
                    {type.label}
                  </Button>
                );
              })}
            </div>
          </div>



          {/* File Upload - Only show for Image/Video */}
          {formData.mediaType !== "text" && (
            <div className="space-y-3">
              <label className="text-sm font-medium text-white">
                {formData.mediaType === "youtube_channel" 
                  ? "YouTube Channel Link" 
                  : `Upload ${formData.mediaType === "image" ? "Image" : "Video"}`}
              </label>

              {/* File Upload Area - Only for Image/Video, not YouTube Channel */}
              {formData.mediaType !== "youtube_channel" && (
                <div className="border-2 border-dashed border-gray-800 rounded-lg p-6 text-center hover:border-gray-700 transition-colors">
                  <Upload className="w-8 h-8 text-gray-500 mx-auto mb-2" />
                  <p className="text-gray-400 mb-2">
                    Click to upload or drag and drop your {formData.mediaType}
                  </p>
                  <p className="text-xs text-gray-500">
                    {formData.mediaType === "image" ? "PNG, JPG, GIF up to 10MB" : "MP4, MOV up to 100MB"}
                  </p>
                  <input
                    type="file"
                    accept={formData.mediaType === "image" ? "image/*" : "video/*"}
                    className="hidden"
                    onChange={async (e) => {
                      const file = e.target.files?.[0];
                      if (file) {
                        setUploading(true);
                        try {
                          const uploadData = new FormData();
                          uploadData.append(formData.mediaType === "image" ? 'image' : 'video', file);
                          const response = await fetch(buildApiUrl('/api/upload'), {
                            method: 'POST',
                            body: uploadData,
                            credentials: 'include',
                          });
                          if (!response.ok) throw new Error('Upload failed');
                          const result = await response.json();
                          setFormData(prev => ({
                            ...prev,
                            mediaUrls: [...prev.mediaUrls, result.url]
                          }));
                          toast({ title: "File uploaded successfully!" });
                        } catch (error) {
                          toast({
                            title: "Upload failed",
                            description: "Could not upload file. Please try again.",
                            variant: "destructive",
                          });
                        } finally {
                          setUploading(false);
                          if (e.target) e.target.value = '';
                        }
                      }
                    }}
                  />
                  <Button
                    type="button"
                    variant="outline"
                    className="mt-2 border-gray-800 text-gray-300 hover:bg-[#0A0A0A]"
                    disabled={uploading}
                    onClick={(e) => {
                      const input = e.currentTarget.parentElement?.querySelector('input[type="file"]') as HTMLInputElement;
                      input?.click();
                    }}
                  >
                    {uploading ? (
                      <>
                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                        Uploading...
                      </>
                    ) : (
                      'Choose File'
                    )}
                  </Button>
                </div>
              )}

              {/* Add Media URL */}
              <div className="space-y-2">
                <label className="text-xs font-medium text-gray-500">
                  {formData.mediaType === "youtube_channel" 
                    ? "Enter your YouTube channel URL:" 
                    : "Or add media URL:"}
                </label>
                <div className="flex gap-2">
                  <Input
                    value={newMediaUrl}
                    onChange={(e) => setNewMediaUrl(e.target.value)}
                    placeholder={
                      formData.mediaType === "youtube_channel" 
                        ? "https://www.youtube.com/@yourchannel or https://www.youtube.com/channel/UCxxx..."
                        : `https://example.com/${formData.mediaType === "image" ? "image.jpg" : "video.mp4"}`
                    }
                    className="bg-[#0A0A0A] border-gray-800 text-white placeholder-gray-500"
                  />
                  <Button
                    type="button"
                    onClick={addMediaUrl}
                    className="bg-gray-800 hover:bg-gray-700 text-white"
                  >
                    Add
                  </Button>
                </div>
              </div>

              {/* Media Preview */}
              {formData.mediaUrls.length > 0 && (
                <div className="space-y-3">
                  <label className="text-sm font-medium text-white">Preview</label>
                  <div className="grid gap-3">
                    {formData.mediaUrls.map((url, index) => (
                      <div key={index} className="relative bg-[#0A0A0A] rounded-lg overflow-hidden border border-gray-800">
                        {formData.mediaType === "youtube_channel" ? (
                          <div className="p-4 flex items-center gap-3">
                            <Youtube className="w-8 h-8 text-red-500" />
                            <div className="flex-1">
                              <p className="text-sm text-white font-medium">YouTube Channel</p>
                              <p className="text-xs text-gray-400 truncate">{url}</p>
                            </div>
                          </div>
                        ) : formData.mediaType === "video" ? (
                          <video
                            controls
                            className="w-full max-h-64 object-contain"
                            style={{ maxHeight: '256px' }}
                          >
                            <source src={url} type="video/mp4" />
                            Your browser does not support the video tag.
                          </video>
                        ) : (
                          <img
                            src={url}
                            alt={`Preview ${index + 1}`}
                            className="w-full max-h-64 object-contain"
                            style={{ maxHeight: '256px' }}
                            onError={(e) => {
                              const target = e.target as HTMLImageElement;
                              target.src = "data:image/svg+xml;base64,";
                            }}
                          />
                        )}

                        {/* Remove button */}
                        <Button
                          type="button"
                          size="sm"
                          variant="destructive"
                          className="absolute top-2 right-2 h-8 w-8 p-0"
                          onClick={() => removeMediaUrl(url)}
                        >
                          <X className="w-4 h-4" />
                        </Button>

                        {/* URL display - Only for non-YouTube channel */}
                        {formData.mediaType !== "youtube_channel" && (
                          <div className="absolute bottom-0 left-0 right-0 bg-black bg-opacity-75 p-2 border-t border-gray-800">
                            <p className="text-xs text-gray-300 truncate">
                              {url}
                            </p>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )}

            </div>
          )}

          {/* Tags */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-white">Tags</label>
            <div className="flex gap-2">
              <Input
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                placeholder="Add a tag..."
                className="bg-[#0A0A0A] border-gray-800 text-white placeholder-gray-500"
                onKeyPress={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    addTag();
                  }
                }}
              />
              <Button
                type="button"
                onClick={addTag}
                className="bg-gray-800 hover:bg-gray-700 text-white"
              >
                Add
              </Button>
            </div>
            {formData.tags.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {formData.tags.map((tag, index) => (
                  <Badge
                    key={index}
                    variant="secondary"
                    className="bg-gray-800 text-white border border-gray-700 flex items-center gap-1"
                  >
                    #{tag}
                    <Button
                      type="button"
                      size="sm"
                      variant="ghost"
                      onClick={() => removeTag(tag)}
                      className="p-0 h-auto text-gray-500 hover:text-white"
                    >
                      <X className="w-3 h-3" />
                    </Button>
                  </Badge>
                ))}
              </div>
            )}
          </div>

          {/* Submit Buttons */}
          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              className="border-gray-800 text-gray-400 hover:bg-gray-900"
            >
              Cancel
            </Button>
            <Button
              type="submit"
              disabled={createPostMutation.isPending}
              className="bg-[#D4AF37] text-black hover:bg-[#B8941F]"
            >
              {createPostMutation.isPending ? "Creating..." : "Create Post"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
    </div>
  );
}

client/src/pages/CreatorProfileManagePag.content:
import React from "react";
import { useAuth } from "@/hooks/useAuth";
import { useCreatorStatus } from "@/hooks/useCreatorStatus";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useToast } from "@/hooks/use-toast";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { ArrowLeft, Plus, Trash2, User, Edit, Save, Calendar, Globe, Users, Play } from "lucide-react";
import { Link, useLocation } from "wouter";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

const platformOptions = [
  "YouTube",
  "TikTok",
  "Instagram",
  "Facebook",
  "Twitter",
  "Twitch",
  "Other",
];

const platformSchema = z.object({
  platform: z.string().min(1, "Platform is required"),
  profileUrl: z.string().url("Please enter a valid URL"),
  subscriberCount: z.number().optional(),
});

const creatorProfileSchema = z.object({
  name: z.string().min(1, "Name is required"),
  content: z.string().min(1, "Content description is required"),
  audience: z.string().optional(),
  bio: z.string().optional(),
  platforms: z.array(platformSchema).min(1, "Please add at least one platform"),
});

type CreatorProfileFormData = z.infer<typeof creatorProfileSchema>;

export default function CreatorProfileManagePage() {
  const { user, isLoading: authLoading } = useAuth();
  const { data: creatorStatus, isLoading: creatorLoading } = useCreatorStatus();
  const [, navigate] = useLocation();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const form = useForm<CreatorProfileFormData>({
    resolver: zodResolver(creatorProfileSchema),
    defaultValues: {
      name: creatorStatus?.creatorProfile?.name || "",
      content: creatorStatus?.creatorProfile?.content || "",
      audience: creatorStatus?.creatorProfile?.audience || "",
      bio: creatorStatus?.creatorProfile?.bio || "",
      platforms: creatorStatus?.creatorProfile?.platforms || [{ platform: "", profileUrl: "", subscriberCount: undefined }],
    },
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "platforms",
  });

  // Update form when creator data loads
  React.useEffect(() => {
    if (creatorStatus?.creatorProfile) {
      const profile = creatorStatus.creatorProfile;
      form.reset({
        name: profile.name,
        content: profile.content,
        audience: profile.audience || "",
        bio: profile.bio || "",
        platforms: profile.platforms.length > 0 ? profile.platforms : [{ platform: "", profileUrl: "", subscriberCount: undefined }],
      });
    }
  }, [creatorStatus, form]);

  const updateProfileMutation = useMutation({
    mutationFn: async (data: CreatorProfileFormData) => {
      if (!creatorStatus?.creatorProfile?.id) {
        throw new Error("Creator profile not found");
      }
      return apiRequest("PUT", `/api/content-creators/${creatorStatus.creatorProfile.id}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/user/creator-status'] });
      toast({
        title: "Profile Updated",
        description: "Your creator profile has been updated successfully.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: CreatorProfileFormData) => {
    updateProfileMutation.mutate(data);
  };

  // Redirect if not authenticated or not a creator
  if (!authLoading && !user) {
    navigate("/auth");
    return null;
  }

  if (!creatorLoading && !creatorStatus?.isCreator) {
    navigate("/");
    return null;
  }

  if (authLoading || creatorLoading) {
    return (
      <div className="min-h-screen bg-black dark:bg-background flex items-center justify-center">
        <div className="animate-spin w-8 h-8 border-4 border-[#D4AF37] border-t-transparent rounded-full"></div>
      </div>
    );
  }

  const creatorProfile = creatorStatus?.creatorProfile;

  return (
    <div className="min-h-screen bg-black dark:bg-background">
      <div className="container mx-auto px-4 py-8">
        {/* Header */}
        <div className="mb-8">
          <Link href="/creators">
            <Button variant="ghost" className="mb-4 text-white dark:text-foreground hover:bg-gray-800 dark:hover:bg-gray-800">
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Creators
            </Button>
          </Link>

          <div className="flex items-center gap-6 mb-6">
            <Avatar className="w-20 h-20">
              <AvatarImage src={creatorProfile?.profileImage || ""} alt={creatorProfile?.name || "Creator"} />
              <AvatarFallback className="bg-gray-800 text-[#D4AF37] text-2xl font-bold">
                {creatorProfile?.name?.split(' ').map(n => n[0]).join('') || 'U'}
              </AvatarFallback>
            </Avatar>

            <div>
              <h1 className="text-3xl font-bold text-white dark:text-foreground">{creatorProfile?.name}</h1>
              <div className="flex items-center gap-2 mt-2">
                <Badge className="bg-[#D4AF37] text-black hover:bg-[#B8941F]">
                  {creatorProfile?.isSponsored ? 'Sponsored Creator' : 'Creator'}
                </Badge>
                {creatorProfile?.isSponsored && (
                  <div className="flex items-center gap-1 text-sm text-gray-400">
                    <Calendar className="w-4 h-4" />
                    <span>Since {new Date().toLocaleDateString()}</span>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Profile Management Form */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Profile Stats */}
          <div className="lg:col-span-1">
            <Card className="bg-gray-900 border-gray-800">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-white">
                  <Users className="w-5 h-5" />
                  Profile Overview
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center gap-2">
                  <Play className="w-4 h-4 text-[#D4AF37]" />
                  <span className="text-sm text-white">Content: {creatorProfile?.content}</span>
                </div>
                {creatorProfile?.audience && (
                  <div className="flex items-center gap-2">
                    <Users className="w-4 h-4 text-[#D4AF37]" />
                    <span className="text-sm text-white">Audience: {creatorProfile.audience}</span>
                  </div>
                )}
                <div className="space-y-2">
                  <p className="text-sm font-medium text-white">Platforms:</p>
                  <div className="flex flex-wrap gap-2">
                    {(creatorProfile?.platforms as any[])?.map((platform, index) => (
                      <div key={index} className="flex items-center gap-1 bg-gray-50 rounded-lg px-3 py-1">
                        <Globe className="w-3 h-3" />
                        <span className="text-xs font-medium text-gray-700 capitalize">
                          {platform.platform}
                        </span>
                        {platform.subscriberCount && (
                          <Badge variant="outline" className="text-xs ml-1 bg-yellow-400 text-black border-yellow-500">
                            {platform.subscriberCount >= 1000000 
                              ? `${(platform.subscriberCount / 1000000).toFixed(1)}M`
                              : platform.subscriberCount >= 1000 
                              ? `${(platform.subscriberCount / 1000).toFixed(1)}K`
                              : platform.subscriberCount}
                          </Badge>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Edit Form */}
          <div className="lg:col-span-2">
            <Card className="bg-gray-900 border-gray-800">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-white">
                  <Edit className="w-5 h-5" />
                  Edit Profile
                </CardTitle>
              </CardHeader>
              <CardContent>
                <Form {...form}>
                  <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                    {/* Basic Information */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <FormField
                        control={form.control}
                        name="name"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Creator Name</FormLabel>
                            <FormControl>
                              <Input {...field} placeholder="Your creator name" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={form.control}
                        name="audience"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Target Audience</FormLabel>
                            <FormControl>
                              <Input {...field} placeholder="e.g., Young adults, Families" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>

                    <FormField
                      control={form.control}
                      name="content"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Content Description</FormLabel>
                          <FormControl>
                            <Textarea {...field} placeholder="Describe the type of content you create" rows={3} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="bio"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Bio</FormLabel>
                          <FormControl>
                            <Textarea {...field} placeholder="Tell us about yourself and your mission" rows={4} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    {/* Platforms */}
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <Label className="text-base font-medium">Social Media Platforms</Label>
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          onClick={() => append({ platform: "", profileUrl: "", subscriberCount: undefined })}
                        >
                          <Plus className="w-4 h-4 mr-2" />
                          Add Platform
                        </Button>
                      </div>

                      {fields.map((field, index) => (
                        <div key={field.id} className="grid grid-cols-1 md:grid-cols-4 gap-4 p-4 border rounded-lg">
                          <FormField
                            control={form.control}
                            name={`platforms.${index}.platform`}
                            render={({ field }) => (
                              <FormItem>
                                <FormLabel>Platform</FormLabel>
                                <Select onValueChange={field.onChange} value={field.value}>
                                  <FormControl>
                                    <SelectTrigger>
                                      <SelectValue placeholder="Select platform" />
                                    </SelectTrigger>
                                  </FormControl>
                                  <SelectContent>
                                    {platformOptions.map((platform) => (
                                      <SelectItem key={platform} value={platform}>
                                        {platform}
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                                <FormMessage />
                              </FormItem>
                            )}
                          />

                          <FormField
                            control={form.control}
                            name={`platforms.${index}.profileUrl`}
                            render={({ field }) => (
                              <FormItem className="md:col-span-2">
                                <FormLabel>Profile URL</FormLabel>
                                <FormControl>
                                  <Input {...field} placeholder="https://..." />
                                </FormControl>
                                <FormMessage />
                              </FormItem>
                            )}
                          />

                          <div className="flex items-end gap-2">
                            <FormField
                              control={form.control}
                              name={`platforms.${index}.subscriberCount`}
                              render={({ field }) => (
                                <FormItem className="flex-1">
                                  <FormLabel>Followers</FormLabel>
                                  <FormControl>
                                    <Input
                                      {...field}
                                      type="number"
                                      placeholder="0"
                                      onChange={(e) => field.onChange(e.target.value ? parseInt(e.target.value) : undefined)}
                                    />
                                  </FormControl>
                                  <FormMessage />
                                </FormItem>
                              )}
                            />

                            {fields.length > 1 && (
                              <Button
                                type="button"
                                variant="outline"
                                size="icon"
                                onClick={() => remove(index)}
                                className="text-red-600 hover:text-red-700"
                              >
                                <Trash2 className="w-4 h-4" />
                              </Button>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    {/* Submit Button */}
                    <div className="flex justify-end">
                      <Button
                        type="submit"
                        disabled={updateProfileMutation.isPending}
                        className="bg-[#D4AF37] hover:bg-[#B8941F] text-black"
                      >
                        {updateProfileMutation.isPending ? (
                          <>
                            <div className="animate-spin w-4 h-4 border-2 border-white border-t-transparent rounded-full mr-2" />
                            Saving...
                          </>
                        ) : (
                          <>
                            <Save className="w-4 h-4 mr-2" />
                            Save Changes
                          </>
                        )}
                      </Button>
                    </div>
                  </form>
                </Form>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </div>
  );
}

