client/src/pages/CreatorSharePage.tsx.content:
import { useState } from "react";
import { useAuth } from "@/hooks/useAuth";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { useLocation, useParams } from "wouter";
import { useEffect } from "react";
import { 
  ArrowLeft,
  Video, 
  Camera, 
  ExternalLink,
  Import,
  Share2,
  AlertCircle,
  CheckCircle,
  Loader2
} from "lucide-react";
import { Helmet } from "react-helmet";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";

export default function CreatorSharePage() {
  const { user, isLoading } = useAuth();
  const [, navigate] = useLocation();
  const params = useParams();
  const platform = params.platform; // youtube, tiktok, instagram
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [contentUrl, setContentUrl] = useState("");
  const [customMessage, setCustomMessage] = useState("");
  const [isImporting, setIsImporting] = useState(false);
  const [importedContent, setImportedContent] = useState<any>(null);

  // Check if user has creator profile
  const { data: creatorStatus } = useQuery({
    queryKey: ["/api/user/creator-status"],
    enabled: !!user,
  });

  // Redirect to login if not authenticated
  useEffect(() => {
    if (!isLoading && !user) {
      navigate("/auth");
    }
  }, [isLoading, user, navigate]);

  // Redirect if not a creator
  useEffect(() => {
    if (user && creatorStatus && !creatorStatus.isCreator) {
      toast({
        title: "Creator Profile Required",
        description: "You need a creator profile to share content from other platforms.",
        variant: "destructive",
      });
      navigate("/creators/profile/manage");
    }
  }, [user, creatorStatus, navigate, toast]);

  const importContentMutation = useMutation({
    mutationFn: async (url: string) => {
      setIsImporting(true);
      return await apiRequest(`/api/creators/import/${platform}`, {
        method: "POST",
        data: { url, platform },
      });
    },
    onSuccess: (data) => {
      setImportedContent(data);
      setIsImporting(false);
      toast({
        title: "Content imported successfully!",
        description: "Review and customize your post before sharing.",
      });
    },
    onError: (error: any) => {
      setIsImporting(false);
      toast({
        title: "Import failed",
        description: error.message || "Failed to import content from this URL.",
        variant: "destructive",
      });
    },
  });

  const shareContentMutation = useMutation({
    mutationFn: async (postData: any) => {
      return await apiRequest("/api/platform-posts", {
        method: "POST",
        data: postData,
      });
    },
    onSuccess: () => {
      toast({ title: "Content shared successfully!" });
      navigate("/feed");
      queryClient.invalidateQueries({ queryKey: ["/api/platform-posts"] });
    },
    onError: (error: any) => {
      toast({
        title: "Failed to share content",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handleImport = () => {
    if (!contentUrl.trim()) {
      toast({
        title: "URL required",
        description: "Please enter a valid URL to import content.",
        variant: "destructive",
      });
      return;
    }
    importContentMutation.mutate(contentUrl.trim());
  };

  const handleShare = () => {
    if (!importedContent) return;

    const postData = {
      title: importedContent.title,
      content: customMessage || importedContent.description || `Check out my latest ${platform} content!`,
      authorType: "creator",
      authorId: creatorStatus?.creatorProfile?.id,
      mediaType: platform === "youtube" ? "video" : "image",
      mediaUrls: [importedContent.thumbnailUrl || importedContent.imageUrl],
      tags: [`#${platform}`, "#creator", "#faith"],
      externalUrl: contentUrl, // Store original URL for linking back
      platform: platform,
    };

    shareContentMutation.mutate(postData);
  };

  const getPlatformInfo = () => {
    switch (platform) {
      case "youtube":
        return {
          name: "YouTube",
          icon: Video,
          color: "text-red-600",
          bgColor: "bg-red-50",
          placeholder: "https://youtube.com/watch?v=...",
          description: "Import videos from your YouTube channel"
        };
      case "tiktok":
        return {
          name: "TikTok", 
          icon: Camera,
          color: "text-pink-600",
          bgColor: "bg-pink-50",
          placeholder: "https://tiktok.com/@username/video/...",
          description: "Import videos from your TikTok profile"
        };
      case "instagram":
        return {
          name: "Instagram",
          icon: Camera, 
          color: "text-purple-600",
          bgColor: "bg-purple-50",
          placeholder: "https://instagram.com/p/...",
          description: "Import posts from your Instagram account"
        };
      default:
        return {
          name: "Platform",
          icon: Share2,
          color: "text-gray-600",
          bgColor: "bg-gray-50",
          placeholder: "Enter content URL...",
          description: "Import content from external platform"
        };
    }
  };

  if (isLoading || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin w-8 h-8 border-4 border-[#D4AF37] border-t-transparent rounded-full" />
      </div>
    );
  }

  const platformInfo = getPlatformInfo();
  const IconComponent = platformInfo.icon;

  return (
    <>
      <Helmet>
        <title>Share {platformInfo.name} Content - Christ Collective</title>
        <meta name="description" content={`Import and share your ${platformInfo.name} content with the Christ Collective community.`} />
      </Helmet>
      <div className="min-h-screen bg-black text-white pb-20">
        {/* Header */}
        <div className="bg-black border-b border-gray-800 p-4 sticky top-0 z-10">
          <div className="flex items-center gap-4">
            <Button 
              variant="ghost" 
              onClick={() => navigate("/create")}
              className="text-white hover:bg-white/10 p-2"
            >
              <ArrowLeft className="w-5 h-5" />
            </Button>
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${platformInfo.bgColor}`}>
                <IconComponent className={`h-6 w-6 ${platformInfo.color}`} />
              </div>
              <div>
                <h1 className="text-xl font-bold text-white">Share {platformInfo.name} Content</h1>
                <p className="text-gray-300 text-sm">{platformInfo.description}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="container mx-auto px-4 py-6 max-w-2xl">
          <div className="space-y-6">
            {/* Import Section */}
            <Card className="bg-gray-900 border-gray-700">
              <CardHeader>
                <CardTitle className="text-white flex items-center gap-2">
                  <Import className="w-5 h-5 text-[#D4AF37]" />
                  Import Content
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-300">
                    {platformInfo.name} URL
                  </label>
                  <div className="flex gap-2">
                    <Input
                      value={contentUrl}
                      onChange={(e) => setContentUrl(e.target.value)}
                      placeholder={platformInfo.placeholder}
                      className="bg-gray-800 border-gray-600 text-white placeholder-gray-400"
                      disabled={isImporting}
                    />
                    <Button
                      onClick={handleImport}
                      disabled={isImporting || !contentUrl.trim()}
                      className="bg-[#D4AF37] text-black hover:bg-[#B8941F]"
                    >
                      {isImporting ? (
                        <Loader2 className="w-4 h-4 animate-spin" />
                      ) : (
                        "Import"
                      )}
                    </Button>
                  </div>
                  <p className="text-xs text-gray-500">
                    Paste the URL of your {platformInfo.name} content to import it
                  </p>
                </div>

                {/* Import Status */}
                {isImporting && (
                  <div className="flex items-center gap-2 text-blue-400">
                    <Loader2 className="w-4 h-4 animate-spin" />
                    <span className="text-sm">Importing content from {platformInfo.name}...</span>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Preview Section */}
            {importedContent && (
              <Card className="bg-gray-900 border-gray-700">
                <CardHeader>
                  <CardTitle className="text-white flex items-center gap-2">
                    <CheckCircle className="w-5 h-5 text-green-500" />
                    Content Preview
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  {/* Content Preview */}
                  <div className="bg-gray-800 rounded-lg p-4">
                    {importedContent.thumbnailUrl && (
                      <img 
                        src={importedContent.thumbnailUrl} 
                        alt={importedContent.title}
                        className="w-full h-48 object-cover rounded-lg mb-3"
                      />
                    )}
                    <h3 className="font-medium text-white mb-2">{importedContent.title}</h3>
                    <p className="text-sm text-gray-400 mb-2">{importedContent.description}</p>
                    <div className="flex items-center gap-2">
                      <Badge variant="secondary" className="text-xs">
                        {platformInfo.name}
                      </Badge>
                      <Button 
                        variant="ghost" 
                        size="sm"
                        onClick={() => window.open(contentUrl, '_blank')}
                        className="text-[#D4AF37] hover:bg-[#D4AF37]/10"
                      >
                        <ExternalLink className="w-3 h-3 mr-1" />
                        View Original
                      </Button>
                    </div>
                  </div>

                  {/* Custom Message */}
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-300">
                      Add Your Message (Optional)
                    </label>
                    <Textarea
                      value={customMessage}
                      onChange={(e) => setCustomMessage(e.target.value)}
                      placeholder={`Share your thoughts about this ${platformInfo.name} content...`}
                      rows={3}
                      className="bg-gray-800 border-gray-600 text-white placeholder-gray-400"
                    />
                  </div>

                  {/* Share Button */}
                  <Button
                    onClick={handleShare}
                    disabled={shareContentMutation.isPending}
                    className="w-full bg-[#D4AF37] text-black hover:bg-[#B8941F]"
                  >
                    {shareContentMutation.isPending ? (
                      <div className="flex items-center gap-2">
                        <Loader2 className="w-4 h-4 animate-spin" />
                        Sharing...
                      </div>
                    ) : (
                      <div className="flex items-center gap-2">
                        <Share2 className="w-4 h-4" />
                        Share with Community
                      </div>
                    )}
                  </Button>
                </CardContent>
              </Card>
            )}

            {/* Info Card */}
            <Card className="bg-gray-900 border-gray-700">
              <CardContent className="p-4">
                <div className="flex items-start gap-3">
                  <AlertCircle className="w-5 h-5 text-blue-400 mt-0.5" />
                  <div>
                    <h4 className="font-medium text-white mb-1">How it works</h4>
                    <ul className="text-sm text-gray-400 space-y-1">
                      <li>• Paste your {platformInfo.name} content URL above</li>
                      <li>• We'll import the title, description, and thumbnail</li>
                      <li>• Add your personal message to share with the community</li>
                      <li>• Your original content link will be preserved for viewers</li>
                    </ul>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </>
  );
}

client/src/pages/MembershipCheckoutPage..content:
import { useState, useEffect } from "react";
import { useParams, useLocation } from "wouter";
import { useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ArrowLeft, Check, Loader2, Crown, HeartHandshake, ArrowRight, ShieldCheck } from "lucide-react";
import { Helmet } from "react-helmet";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";

const tierDetails: Record<string, { name: string; price: string; icon: any; benefits: string[]; emoji: string }> = {
  collective: {
    name: "The Collective",
    price: "$30/month",
    icon: HeartHandshake,
    emoji: "🕊️",
    benefits: [
      "Access to the Christ Collective private community & member directory",
      "Weekly team leader program calls",
      "Bi-weekly networking calls",
      "Spiritual counsel access",
      "Public outreach & ministry events",
      "Private member events — standard access",
      "Shared resource library & newsletter"
    ]
  },
  guild: {
    name: "The Guild",
    price: "$60/month",
    icon: Crown,
    emoji: "✨",
    benefits: [
      "Everything in The Collective",
      "Priority access to private events",
      "Early access to programs & collabs",
      "Pitch & co-lead collective projects",
      "Private member events — priority access",
      "Featured Guild member recognition"
    ]
  }
};

export default function MembershipCheckoutPage() {
  const { tierId } = useParams();
  const [, navigate] = useLocation();
  const { toast } = useToast();
  const { user, isLoading: isAuthLoading } = useAuth();

  const [fullName, setFullName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");

  useEffect(() => {
    if (user) {
      const u = user as any;
      const name = u.displayName || (u.firstName && u.lastName ? `${u.firstName} ${u.lastName}` : u.firstName || u.username || "");
      if (name && !fullName) setFullName(name);
      if (u.email && !email) setEmail(u.email);
      if (u.phone && !phone) setPhone(u.phone);
    }
  }, [user]);

  const tier = tierId ? tierDetails[tierId] : null;

  const subscribeMutation = useMutation({
    mutationFn: async (data: { tier: string; fullName: string; email: string; phone: string }) => {
      const res = await apiRequest("/api/membership-subscriptions", {
        method: "POST",
        data,
      });
      return res.json();
    },
    onSuccess: (data: { checkoutUrl: string; subscriptionId: number }) => {
      if (data.checkoutUrl) {
        window.location.href = data.checkoutUrl;
      } else {
        toast({
          title: "Error",
          description: "Unable to start checkout. Please try again.",
          variant: "destructive",
        });
      }
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message || "Failed to create membership. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fullName.trim() || !email.trim()) {
      toast({
        title: "Missing information",
        description: "Please fill in your full name and email.",
        variant: "destructive",
      });
      return;
    }
    subscribeMutation.mutate({
      tier: tierId || "",
      fullName: fullName.trim(),
      email: email.trim(),
      phone: phone.trim(),
    });
  };

  if (isAuthLoading) {
    return (
      <div className="min-h-screen bg-black text-white flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-[#D4AF37]" />
      </div>
    );
  }

  if (!user) {
    navigate(`/auth?redirect=/membership/checkout/${tierId}`);
    return null;
  }

  if (!tier || !tierId) {
    return (
      <div className="min-h-screen bg-black text-white flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold mb-4">Membership tier not found</h2>
          <p className="text-gray-400 mb-6">The membership tier you selected doesn't exist.</p>
          <Button className="bg-[#D4AF37] text-black" onClick={() => navigate("/memberships")}>
            View Memberships
          </Button>
        </div>
      </div>
    );
  }

  const TierIcon = tier.icon;

  return (
    <>
      <Helmet>
        <title>Join {tier.name} | Christ Collective</title>
        <meta name="description" content={`Subscribe to ${tier.name} and unlock exclusive membership benefits at Christ Collective.`} />
      </Helmet>

      <div className="min-h-screen bg-black text-white pb-24">
        <div className="container mx-auto px-4 py-8">
          <Button
            variant="ghost"
            className="text-gray-400 hover:text-white mb-6"
            onClick={() => navigate("/memberships")}
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Memberships
          </Button>

          <div className="max-w-4xl mx-auto grid grid-cols-1 lg:grid-cols-5 gap-8">
            <div className="lg:col-span-2">
              <Card className="bg-gradient-to-b from-[#D4AF37]/15 via-[#0A0A0A] to-[#0A0A0A] border-[#D4AF37]/40 sticky top-8">
                <CardHeader className="text-center pb-4">
                  <div className="inline-flex p-3 rounded-2xl bg-[#D4AF37]/10 ring-1 ring-[#D4AF37]/30 mx-auto mb-3">
                    <TierIcon className="w-7 h-7 text-[#D4AF37]" />
                  </div>
                  <CardTitle className="text-xl text-[#D4AF37] flex items-center justify-center gap-2">
                    <span>{tier.emoji}</span> {tier.name}
                  </CardTitle>
                  <p className="text-3xl font-bold text-white mt-2">{tier.price}</p>
                </CardHeader>
                <CardContent className="pt-0">
                  <Separator className="bg-[#D4AF37]/20 mb-4" />
                  <ul className="space-y-3">
                    {tier.benefits.map((benefit, i) => (
                      <li key={i} className="flex items-start gap-2.5 text-sm">
                        <div className="mt-0.5 rounded-full p-0.5 bg-[#D4AF37]/20 flex-shrink-0">
                          <Check className="w-3 h-3 text-[#D4AF37]" />
                        </div>
                        <span className="text-gray-300 leading-tight">{benefit}</span>
                      </li>
                    ))}
                  </ul>
                </CardContent>
                <CardFooter className="pt-0">
                  <div className="flex items-center gap-2 text-xs text-gray-500 w-full justify-center">
                    <ShieldCheck className="w-3.5 h-3.5" />
                    <span>Cancel anytime</span>
                  </div>
                </CardFooter>
              </Card>
            </div>

            <div className="lg:col-span-3">
              <Card className="bg-[#0A0A0A] border-gray-800">
                <CardHeader>
                  <CardTitle className="text-xl text-white">Your Information</CardTitle>
                  <p className="text-gray-500 text-sm">
                    Please provide your details to complete your membership registration.
                  </p>
                </CardHeader>
                <CardContent>
                  <form onSubmit={handleSubmit} className="space-y-5">
                    <div className="space-y-2">
                      <Label htmlFor="fullName" className="text-gray-300">Full Name *</Label>
                      <Input
                        id="fullName"
                        value={fullName}
                        onChange={(e) => setFullName(e.target.value)}
                        placeholder="Enter your full name"
                        className="bg-black border-gray-700 text-white placeholder:text-gray-600 focus:border-[#D4AF37]"
                        required
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="email" className="text-gray-300">Email Address *</Label>
                      <Input
                        id="email"
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        placeholder="Enter your email address"
                        className="bg-black border-gray-700 text-white placeholder:text-gray-600 focus:border-[#D4AF37]"
                        required
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="phone" className="text-gray-300">Phone Number</Label>
                      <Input
                        id="phone"
                        type="tel"
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        placeholder="Enter your phone number (optional)"
                        className="bg-black border-gray-700 text-white placeholder:text-gray-600 focus:border-[#D4AF37]"
                      />
                    </div>

                    <Separator className="bg-gray-800" />

                    <div className="bg-black/50 border border-gray-800 rounded-lg p-4">
                      <h3 className="text-sm font-semibold text-gray-300 mb-2">Order Summary</h3>
                      <div className="flex justify-between text-sm mb-1">
